   125  class EventTargetChainItem {
   126   public:
   127    explicit EventTargetChainItem(EventTarget* aTarget)
   128        : mTarget(aTarget), mItemFlags(0) {
   129      MOZ_COUNT_CTOR(EventTargetChainItem);
