  1380  nsresult EventDispatcher::DispatchDOMEvent(EventTarget* aTarget,
  1381                                             WidgetEvent* aEvent,
  1382                                             Event* aDOMEvent,
  1383                                             nsPresContext* aPresContext,
  1384                                             nsEventStatus* aEventStatus) {
  1385    if (aDOMEvent) {
  1386      WidgetEvent* innerEvent = aDOMEvent->WidgetEventPtr();
  1387      NS_ENSURE_TRUE(innerEvent, NS_ERROR_ILLEGAL_VALUE);
  1388
  1389      // Don't modify the event if it's being dispatched right now.
  1390      if (innerEvent->mFlags.mIsBeingDispatched) {
  1391        return NS_ERROR_DOM_INVALID_STATE_ERR;
  1392      }
  1393
  1394      bool dontResetTrusted = false;
  1395      if (innerEvent->mFlags.mDispatchedAtLeastOnce) {
  1396        innerEvent->mTarget = nullptr;
  1397        innerEvent->mOriginalTarget = nullptr;
  1398      } else {
  1399        dontResetTrusted = aDOMEvent->IsTrusted();
  1400      }
  1401
  1402      if (!dontResetTrusted) {
  1403        // Check security state to determine if dispatcher is trusted
  1404        bool trusted = NS_IsMainThread()
  1405                           ? nsContentUtils::LegacyIsCallerChromeOrNativeCode()
  1406                           : IsCurrentThreadRunningChromeWorker();
  1407        aDOMEvent->SetTrusted(trusted);
  1408      }
  1409
  1410      return EventDispatcher::Dispatch(aTarget, aPresContext, innerEvent,
  1411                                       aDOMEvent, aEventStatus);
  1412    } else if (aEvent) {
  1413      return EventDispatcher::Dispatch(aTarget, aPresContext, aEvent, aDOMEvent,
  1414                                       aEventStatus);
  1415    }
  1416    return NS_ERROR_ILLEGAL_VALUE;
  1417  }
