  1419  /* static */ already_AddRefed<dom::Event> EventDispatcher::CreateEvent(
  1420      EventTarget* aOwner, nsPresContext* aPresContext, WidgetEvent* aEvent,
  1421      const nsAString& aEventType, CallerType aCallerType) {
  1422    if (aEvent) {
  1423      switch (aEvent->mClass) {
  1424        case eGUIEventClass:
  1425        case eScrollPortEventClass:
  1426        case eUIEventClass:
  1427          return NS_NewDOMUIEvent(aOwner, aPresContext, aEvent->AsGUIEvent());
  1428        case eScrollAreaEventClass:
  1429          return NS_NewDOMScrollAreaEvent(aOwner, aPresContext,
  1430                                          aEvent->AsScrollAreaEvent());
  1431        case eKeyboardEventClass:
  1432          return NS_NewDOMKeyboardEvent(aOwner, aPresContext,
  1433                                        aEvent->AsKeyboardEvent());
  1434        case eCompositionEventClass:
  1435          return NS_NewDOMCompositionEvent(aOwner, aPresContext,
  1436                                           aEvent->AsCompositionEvent());
  1437        case eMouseEventClass:
  1438          return NS_NewDOMMouseEvent(aOwner, aPresContext,
  1439                                     aEvent->AsMouseEvent());
  1440        case eFocusEventClass:
  1441          return NS_NewDOMFocusEvent(aOwner, aPresContext,
  1442                                     aEvent->AsFocusEvent());
  1443        case eMouseScrollEventClass:
  1444          return NS_NewDOMMouseScrollEvent(aOwner, aPresContext,
  1445                                           aEvent->AsMouseScrollEvent());
  1446        case eWheelEventClass:
  1447          return NS_NewDOMWheelEvent(aOwner, aPresContext,
  1448                                     aEvent->AsWheelEvent());
  1449        case eEditorInputEventClass:
  1450          return NS_NewDOMInputEvent(aOwner, aPresContext,
  1451                                     aEvent->AsEditorInputEvent());
  1452        case eLegacyTextEventClass:
  1453          return NS_NewDOMTextEvent(aOwner, aPresContext,
  1454                                    aEvent->AsLegacyTextEvent());
  1455        case eDragEventClass:
  1456          return NS_NewDOMDragEvent(aOwner, aPresContext, aEvent->AsDragEvent());
  1457        case eClipboardEventClass:
  1458          return NS_NewDOMClipboardEvent(aOwner, aPresContext,
  1459                                         aEvent->AsClipboardEvent());
  1460        case eSMILTimeEventClass:
  1461          return NS_NewDOMTimeEvent(aOwner, aPresContext,
  1462                                    aEvent->AsSMILTimeEvent());
  1463        case eCommandEventClass:
  1464          return NS_NewDOMCommandEvent(aOwner, aPresContext,
  1465                                       aEvent->AsCommandEvent());
  1466        case eSimpleGestureEventClass:
  1467          return NS_NewDOMSimpleGestureEvent(aOwner, aPresContext,
  1468                                             aEvent->AsSimpleGestureEvent());
  1469        case ePointerEventClass:
  1470          return NS_NewDOMPointerEvent(aOwner, aPresContext,
  1471                                       aEvent->AsPointerEvent());
  1472        case eTouchEventClass:
  1473          return NS_NewDOMTouchEvent(aOwner, aPresContext,
  1474                                     aEvent->AsTouchEvent());
  1475        case eTransitionEventClass:
  1476          return NS_NewDOMTransitionEvent(aOwner, aPresContext,
  1477                                          aEvent->AsTransitionEvent());
  1478        case eAnimationEventClass:
  1479          return NS_NewDOMAnimationEvent(aOwner, aPresContext,
  1480                                         aEvent->AsAnimationEvent());
  1481        default:
  1482          // For all other types of events, create a vanilla event object.
  1483          return NS_NewDOMEvent(aOwner, aPresContext, aEvent);
  1484      }
  1485    }
  1486
  1487    // And if we didn't get an event, check the type argument.
  1488
  1489    if (aEventType.LowerCaseEqualsLiteral("mouseevent") ||
  1490        aEventType.LowerCaseEqualsLiteral("mouseevents")) {
  1491      return NS_NewDOMMouseEvent(aOwner, aPresContext, nullptr);
  1492    }
  1493    if (aEventType.LowerCaseEqualsLiteral("dragevent")) {
  1494      return NS_NewDOMDragEvent(aOwner, aPresContext, nullptr);
  1495    }
  1496    if (aEventType.LowerCaseEqualsLiteral("keyboardevent")) {
  1497      return NS_NewDOMKeyboardEvent(aOwner, aPresContext, nullptr);
  1498    }
  1499    if (aEventType.LowerCaseEqualsLiteral("compositionevent")) {
  1500      return NS_NewDOMCompositionEvent(aOwner, aPresContext, nullptr);
  1501    }
  1502    if (aEventType.LowerCaseEqualsLiteral("textevent")) {
  1503      if (!StaticPrefs::dom_events_textevent_enabled()) {
  1504        return NS_NewDOMCompositionEvent(aOwner, aPresContext, nullptr);
  1505      }
  1506      return NS_NewDOMTextEvent(aOwner, aPresContext, nullptr);
  1507    }
  1508    if (aEventType.LowerCaseEqualsLiteral("deviceorientationevent")) {
  1509      DeviceOrientationEventInit init;
  1510      RefPtr<Event> event =
  1511          DeviceOrientationEvent::Constructor(aOwner, u""_ns, init);
  1512      event->MarkUninitialized();
  1513      return event.forget();
  1514    }
  1515    if (aEventType.LowerCaseEqualsLiteral("devicemotionevent")) {
  1516      return NS_NewDOMDeviceMotionEvent(aOwner, aPresContext, nullptr);
  1517    }
  1518    if (aEventType.LowerCaseEqualsLiteral("uievent") ||
  1519        aEventType.LowerCaseEqualsLiteral("uievents")) {
  1520      return NS_NewDOMUIEvent(aOwner, aPresContext, nullptr);
  1521    }
  1522    if (aEventType.LowerCaseEqualsLiteral("event") ||
  1523        aEventType.LowerCaseEqualsLiteral("events") ||
  1524        aEventType.LowerCaseEqualsLiteral("htmlevents") ||
  1525        aEventType.LowerCaseEqualsLiteral("svgevents")) {
  1526      return NS_NewDOMEvent(aOwner, aPresContext, nullptr);
  1527    }
  1528    if (aEventType.LowerCaseEqualsLiteral("messageevent")) {
  1529      RefPtr<Event> event = new MessageEvent(aOwner, aPresContext, nullptr);
  1530      return event.forget();
  1531    }
  1532    if (aEventType.LowerCaseEqualsLiteral("beforeunloadevent")) {
  1533      return NS_NewDOMBeforeUnloadEvent(aOwner, aPresContext, nullptr);
  1534    }
  1535    if (aEventType.LowerCaseEqualsLiteral("touchevent") &&
  1536        TouchEvent::LegacyAPIEnabled(
  1537            nsContentUtils::GetDocShellForEventTarget(aOwner),
  1538            aCallerType == CallerType::System)) {
  1539      return NS_NewDOMTouchEvent(aOwner, aPresContext, nullptr);
  1540    }
  1541    if (aEventType.LowerCaseEqualsLiteral("hashchangeevent")) {
  1542      HashChangeEventInit init;
  1543      RefPtr<Event> event = HashChangeEvent::Constructor(aOwner, u""_ns, init);
  1544      event->MarkUninitialized();
  1545      return event.forget();
  1546    }
  1547    if (aEventType.LowerCaseEqualsLiteral("customevent")) {
  1548      return NS_NewDOMCustomEvent(aOwner, aPresContext, nullptr);
  1549    }
  1550    if (aEventType.LowerCaseEqualsLiteral("storageevent")) {
  1551      RefPtr<Event> event =
  1552          StorageEvent::Constructor(aOwner, u""_ns, StorageEventInit());
  1553      event->MarkUninitialized();
  1554      return event.forget();
  1555    }
  1556    if (aEventType.LowerCaseEqualsLiteral("focusevent")) {
  1557      RefPtr<Event> event = NS_NewDOMFocusEvent(aOwner, aPresContext, nullptr);
  1558      event->MarkUninitialized();
  1559      return event.forget();
  1560    }
  1561
  1562    // Only allow these events for chrome
  1563    if (aCallerType == CallerType::System) {
  1564      if (aEventType.LowerCaseEqualsLiteral("simplegestureevent")) {
  1565        return NS_NewDOMSimpleGestureEvent(aOwner, aPresContext, nullptr);
  1566      }
  1567      if (aEventType.LowerCaseEqualsLiteral("xulcommandevent") ||
  1568          aEventType.LowerCaseEqualsLiteral("xulcommandevents")) {
  1569        return NS_NewDOMXULCommandEvent(aOwner, aPresContext, nullptr);
  1570      }
  1571    }
  1572
  1573    // NEW EVENT TYPES SHOULD NOT BE ADDED HERE; THEY SHOULD USE ONLY EVENT
  1574    // CONSTRUCTORS
  1575
  1576    return nullptr;
  1577  }
