  1584  static CurrentTargetPathInfo TargetPathInfo(
  1585      const nsTArray<EventTargetChainItem>& aEventPath,
  1586      const EventTarget& aCurrentTarget) {
  1587    int32_t currentTargetHiddenSubtreeLevel = 0;
  1588    for (uint32_t index = aEventPath.Length(); index--;) {
  1589      const EventTargetChainItem& item = aEventPath.ElementAt(index);
  1590      if (item.PreHandleEventOnly()) {
  1591        continue;
  1592      }
  1593
  1594      if (item.IsRootOfClosedTree()) {
  1595        currentTargetHiddenSubtreeLevel++;
  1596      }
  1597
  1598      if (item.CurrentTarget() == &aCurrentTarget) {
  1599        return {index, currentTargetHiddenSubtreeLevel};
  1600      }
  1601
  1602      if (item.IsSlotInClosedTree()) {
  1603        currentTargetHiddenSubtreeLevel--;
  1604      }
  1605    }
  1606    MOZ_ASSERT_UNREACHABLE("No target found?");
  1607    return {0, 0};
  1608  }
